// Filter rows: keep only posts where:
// - Status === "Scheduled"
// - Scheduled time <= now
// - retry_count < 3
const now = new Date();
const items = $input.all();
const out = [];
for (const it of items) {
  const r = it.json;
  if (String(r.Status || '').trim().toLowerCase() !== 'scheduled') continue;
  const due = r['Scheduled Time'] ? new Date(r['Scheduled Time']) : null;
  if (!due || isNaN(due.getTime()) || due > now) continue;
  const retries = parseInt(r['Retry Count'] || '0', 10);
  if (isNaN(retries) || retries >= 3) continue;
  // Normalize platforms list
  let platforms = String(r.Platforms || '').split(',').map(s => s.trim().toLowerCase()).filter(Boolean);
  // Default if column is empty -> publish to all
  if (platforms.length === 0) platforms = ['instagram', 'facebook', 'linkedin'];
  out.push({
    json: {
      row_id: r['Row ID'] || r['Post ID'] || '',
      original_caption: r.Caption || '',
      media_url: r['Media URL'] || '',
      media_type: r['Media Type'] || 'image',
      scheduled_time: r['Scheduled Time'],
      platforms,
      retry_count: retries,
      author_urn: r['LinkedIn Author URN'] || '',
      ig_user_id: r['Instagram User ID'] || '',
      fb_page_id: r['Facebook Page ID'] || '',
      fb_access_token: r['Meta Access Token'] || '',
      li_access_token: r['LinkedIn Access Token'] || ''
    }
  });
}
return out;

