// Pull the AI Agent output (it is the JSON string returned by the structured parser)
const raw = $('AI Enhance Content').first().json;
// Output parser typically returns the parsed object in $json.output
let parsed = raw.output || raw;
if (typeof parsed === 'string') {
  try { parsed = JSON.parse(parsed); } catch (e) { throw new Error('AI did not return valid JSON: ' + parsed); }
}

const platforms = parsed.platforms || {};
const score = Number(parsed.quality_score || 0);

// Build a flat per-platform caption+hashtags bundle
const buildText = (p) => {
  if (!p) return '';
  const tags = (p.hashtags || []).join(' ');
  return p.caption + (tags ? '\n\n' + tags : '');
};

return [{
  json: {
    row_id: $('Loop Over Posts').item.json.row_id,
    retry_count: $('Loop Over Posts').item.json.retry_count,
    platforms: $('Loop Over Posts').item.json.platforms,
    media_url: $('Loop Over Posts').item.json.media_url,
    media_type: $('Loop Over Posts').item.json.media_type,
    author_urn: $('Loop Over Posts').item.json.author_urn,
    ig_user_id: $('Loop Over Posts').item.json.ig_user_id,
    fb_page_id: $('Loop Over Posts').item.json.fb_page_id,
    fb_access_token: $('Loop Over Posts').item.json.fb_access_token,
    li_access_token: $('Loop Over Posts').item.json.li_access_token,
    quality_score: score,
    quality_feedback: parsed.quality_feedback || '',
    instagram: {
      text: buildText(platforms.instagram),
      has_ig: $('Loop Over Posts').item.json.platforms.includes('instagram')
    },
    facebook: {
      text: buildText(platforms.facebook),
      has_fb: $('Loop Over Posts').item.json.platforms.includes('facebook')
    },
    linkedin: {
      text: buildText(platforms.linkedin),
      has_li: $('Loop Over Posts').item.json.platforms.includes('linkedin')
    }
  }
}];

// Collect results from the 3 publishes (Instagram has 2 calls - we treat the publish step as the source of truth)
const igPub = $('IG - Publish Container').first().json;
const fbPub = $('Facebook - Publish Photo').first().json;
const liPub = $('LinkedIn - Publish Post').first().json;

const igOk = igPub && !igPub.error && igPub.id;
const fbOk = fbPub && !fbPub.error && (fbPub.id || fbPub.post_id);
const liOk = liPub && !liPub.error && liPub.id;

return [{
  json: {
    row_id: $('Parse AI Output').item.json.row_id,
    retry_count: $('Parse AI Output').item.json.retry_count,
    platforms: $('Parse AI Output').item.json.platforms,
    ig_ok: !!igOk,
    fb_ok: !!fbOk,
    li_ok: !!liOk,
    all_ok: !!(igOk && fbOk && liOk),
    ig_response: igPub,
    fb_response: fbPub,
    li_response: liPub
  }
}];

// Centralized error record builder. Triggered by:
// - Quality Check fail (low AI score)
// - All Platforms OK? = false (partial or full publish failure)
const items = $input.all();
const out = [];
for (const it of items) {
  const r = it.json;
  const failed = [];
  if (r.ig_ok === false) failed.push('Instagram');
  if (r.fb_ok === false) failed.push('Facebook');
  if (r.li_ok === false) failed.push('LinkedIn');
  const reason = r.quality_score !== undefined && r.quality_score < 60
    ? `Quality check failed (score ${r.quality_score}): ${r.quality_feedback || ''}`
    : `Publish failed on: ${failed.join(', ') || 'unknown'}`;
  out.push({
    json: {
      timestamp: new Date().toISOString(),
      row_id: r.row_id || '',
      reason,
      retry_count: r.retry_count || 0,
      platforms: Array.isArray(r.platforms) ? r.platforms.join(',') : (r.platforms || ''),
      original_caption: r.original_caption || '',
      quality_score: r.quality_score || null,
      ig_error: r.ig_response && r.ig_response.error ? JSON.stringify(r.ig_response.error) : '',
      fb_error: r.fb_response && r.fb_response.error ? JSON.stringify(r.fb_response.error) : '',
      li_error: r.li_response && r.li_response.error ? JSON.stringify(r.li_response.error) : ''
    }
  });
}
return out;

